import{_ as e,c as r,o as l,ag as i}from"./chunks/framework.dvv-DFtf.js";const c=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":null}'),t={name:"guide/faq.md"};function o(h,a,n,d,u,s){return l(),r("div",null,[...a[0]||(a[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\faq.md for this page in Markdown format</div><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="账号与认证" tabindex="-1">账号与认证 <a class="header-anchor" href="#账号与认证" aria-label="Permalink to &quot;账号与认证&quot;">​</a></h2><h3 id="q-如何注册账号" tabindex="-1">Q: 如何注册账号？ <a class="header-anchor" href="#q-如何注册账号" aria-label="Permalink to &quot;Q: 如何注册账号？&quot;">​</a></h3><p>访问 <a href="https://api.lurus.cn" target="_blank" rel="noreferrer">api.lurus.cn</a>，点击注册，填写邮箱和密码即可。</p><h3 id="q-api-key-丢失了怎么办" tabindex="-1">Q: API Key 丢失了怎么办？ <a class="header-anchor" href="#q-api-key-丢失了怎么办" aria-label="Permalink to &quot;Q: API Key 丢失了怎么办？&quot;">​</a></h3><p>API Key 无法找回，请登录控制台创建新的 Key。</p><h3 id="q-为什么提示-api-key-无效" tabindex="-1">Q: 为什么提示 API Key 无效？ <a class="header-anchor" href="#q-为什么提示-api-key-无效" aria-label="Permalink to &quot;Q: 为什么提示 API Key 无效？&quot;">​</a></h3><ul><li>检查 Key 是否完整复制（以 <code>sk-</code> 开头）</li><li>确认 Key 状态为「启用」</li><li>检查是否有多余空格</li></ul><h2 id="模型与调用" tabindex="-1">模型与调用 <a class="header-anchor" href="#模型与调用" aria-label="Permalink to &quot;模型与调用&quot;">​</a></h2><h3 id="q-支持哪些模型" tabindex="-1">Q: 支持哪些模型？ <a class="header-anchor" href="#q-支持哪些模型" aria-label="Permalink to &quot;Q: 支持哪些模型？&quot;">​</a></h3><p>支持 OpenAI、Claude、Gemini、DeepSeek 等主流模型，详见 <a href="/guide/models">模型列表</a>。</p><h3 id="q-提示-no-available-server" tabindex="-1">Q: 提示 &quot;no available server&quot;？ <a class="header-anchor" href="#q-提示-no-available-server" aria-label="Permalink to &quot;Q: 提示 &quot;no available server&quot;？&quot;">​</a></h3><ul><li>检查模型名称是否正确</li><li>确认你的 Key 有权限访问该模型</li><li>该模型可能暂时没有可用渠道，请联系管理员</li></ul><h3 id="q-如何切换模型" tabindex="-1">Q: 如何切换模型？ <a class="header-anchor" href="#q-如何切换模型" aria-label="Permalink to &quot;Q: 如何切换模型？&quot;">​</a></h3><p>只需更改请求中的 <code>model</code> 参数，其他代码无需修改。</p><h3 id="q-流式响应如何使用" tabindex="-1">Q: 流式响应如何使用？ <a class="header-anchor" href="#q-流式响应如何使用" aria-label="Permalink to &quot;Q: 流式响应如何使用？&quot;">​</a></h3><p>在请求中设置 <code>&quot;stream&quot;: true</code>，响应将通过 SSE 逐块返回。</p><h2 id="计费与配额" tabindex="-1">计费与配额 <a class="header-anchor" href="#计费与配额" aria-label="Permalink to &quot;计费与配额&quot;">​</a></h2><h3 id="q-如何查看用量" tabindex="-1">Q: 如何查看用量？ <a class="header-anchor" href="#q-如何查看用量" aria-label="Permalink to &quot;Q: 如何查看用量？&quot;">​</a></h3><p>登录控制台，在「数据看板」或「使用日志」中查看。</p><h3 id="q-配额用完了怎么办" tabindex="-1">Q: 配额用完了怎么办？ <a class="header-anchor" href="#q-配额用完了怎么办" aria-label="Permalink to &quot;Q: 配额用完了怎么办？&quot;">​</a></h3><p>联系管理员充值或升级套餐。</p><h3 id="q-不同模型的价格" tabindex="-1">Q: 不同模型的价格？ <a class="header-anchor" href="#q-不同模型的价格" aria-label="Permalink to &quot;Q: 不同模型的价格？&quot;">​</a></h3><p>详见 <a href="/guide/models">模型列表</a> 中的定价信息。</p><h2 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h2><h3 id="q-请求超时怎么办" tabindex="-1">Q: 请求超时怎么办？ <a class="header-anchor" href="#q-请求超时怎么办" aria-label="Permalink to &quot;Q: 请求超时怎么办？&quot;">​</a></h3><ul><li>检查网络连接</li><li>尝试减少 <code>max_tokens</code></li><li>某些复杂请求需要更长时间</li></ul><h3 id="q-返回-429-错误" tabindex="-1">Q: 返回 429 错误？ <a class="header-anchor" href="#q-返回-429-错误" aria-label="Permalink to &quot;Q: 返回 429 错误？&quot;">​</a></h3><p>请求频率过高，请降低调用频率或联系管理员提高限制。</p><h3 id="q-上下文长度超限" tabindex="-1">Q: 上下文长度超限？ <a class="header-anchor" href="#q-上下文长度超限" aria-label="Permalink to &quot;Q: 上下文长度超限？&quot;">​</a></h3><ul><li>减少输入内容</li><li>截断历史消息</li><li>切换到支持更长上下文的模型</li></ul><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><h3 id="q-数据安全吗" tabindex="-1">Q: 数据安全吗？ <a class="header-anchor" href="#q-数据安全吗" aria-label="Permalink to &quot;Q: 数据安全吗？&quot;">​</a></h3><ul><li>全程 HTTPS 加密传输</li><li>不会存储你的对话内容</li><li>仅记录调用元数据用于计费</li></ul><h3 id="q-有-sla-保证吗" tabindex="-1">Q: 有 SLA 保证吗？ <a class="header-anchor" href="#q-有-sla-保证吗" aria-label="Permalink to &quot;Q: 有 SLA 保证吗？&quot;">​</a></h3><p>企业客户可签订 SLA 协议，请联系商务。</p><h3 id="q-如何获取技术支持" tabindex="-1">Q: 如何获取技术支持？ <a class="header-anchor" href="#q-如何获取技术支持" aria-label="Permalink to &quot;Q: 如何获取技术支持？&quot;">​</a></h3><ul><li>邮箱: <a href="mailto:support@lurus.cn" target="_blank" rel="noreferrer">support@lurus.cn</a></li><li>GitHub Issues</li></ul><hr><p>没有找到答案？请 <a href="mailto:support@lurus.cn" target="_blank" rel="noreferrer">联系我们</a>。</p>',41)])])}const b=e(t,[["render",o]]);export{c as __pageData,b as default};
